import { useEffect, useState } from 'react';
import AdminMentorLayout from '../components/AdminMentorLayout.jsx';
import { ErrorState, LoadingState } from '../components/LoadingState.jsx';
import StatusBadge from '../components/StatusBadge.jsx';
import { adminMentorApi } from '../services/api.js';
import { formatDateTime } from '../utils/formatters.js';

const roleOptions = ['ALL', 'ADMIN', 'MENTOR', 'LEARNER'];
const statusOptions = ['ALL', 'ACTIVE', 'BLOCKED', 'PENDING_VERIFICATION'];

export default function UserManagementPage() {
  const [users, setUsers] = useState([]);
  const [filters, setFilters] = useState({ search: '', role: 'ALL', status: 'ALL' });
  const [loading, setLoading] = useState(true);
  const [updatingUserId, setUpdatingUserId] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    let mounted = true;

    setLoading(true);
    adminMentorApi
      .getAdminUsers(filters)
      .then((response) => {
        if (mounted) {
          setUsers(response.data);
          setError('');
        }
      })
      .catch((requestError) => {
        if (mounted) {
          setError(requestError.message);
        }
      })
      .finally(() => {
        if (mounted) {
          setLoading(false);
        }
      });

    return () => {
      mounted = false;
    };
  }, [filters]);

  const updateFilter = (fieldName, value) => {
    setFilters((current) => ({ ...current, [fieldName]: value }));
  };

  const handleStatusChange = async (user, nextStatus) => {
    setUpdatingUserId(user.id);
    setError('');

    try {
      // Xu ly block/unblock trong mock de demo UI. Backend that se kiem tra role ADMIN, payment/enrollment va ghi audit log.
      const response = await adminMentorApi.updateUserStatus(user.id, nextStatus);
      setUsers((currentUsers) =>
        currentUsers.map((item) => (item.id === user.id ? response.data : item)),
      );
    } catch (requestError) {
      setError(requestError.message || 'Khong the cap nhat trang thai user.');
    } finally {
      setUpdatingUserId('');
    }
  };

  return (
    <AdminMentorLayout
      area="admin"
      title="User Management"
      subtitle="Quan ly tai khoan Admin, Mentor, Learner va trang thai dang nhap."
    >
      <div className="card admin-mentor-card mb-4">
        <div className="card-body">
          <div className="row g-3 align-items-end">
            <div className="col-12 col-lg-5">
              <label className="form-label" htmlFor="admin-user-search">
                Search
              </label>
              <input
                className="form-control"
                id="admin-user-search"
                onChange={(event) => updateFilter('search', event.target.value)}
                placeholder="Search name or email"
                type="search"
                value={filters.search}
              />
            </div>
            <div className="col-6 col-lg-3">
              <label className="form-label" htmlFor="admin-user-role">
                Role
              </label>
              <select
                className="form-select"
                id="admin-user-role"
                onChange={(event) => updateFilter('role', event.target.value)}
                value={filters.role}
              >
                {roleOptions.map((role) => (
                  <option key={role} value={role}>
                    {role}
                  </option>
                ))}
              </select>
            </div>
            <div className="col-6 col-lg-3">
              <label className="form-label" htmlFor="admin-user-status">
                Status
              </label>
              <select
                className="form-select"
                id="admin-user-status"
                onChange={(event) => updateFilter('status', event.target.value)}
                value={filters.status}
              >
                {statusOptions.map((status) => (
                  <option key={status} value={status}>
                    {status}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>
      </div>

      {loading ? <LoadingState message="Dang tai danh sach user..." /> : null}
      {!loading && error ? <ErrorState message={error} /> : null}

      {!loading ? (
        <div className="card admin-mentor-card">
          <div className="card-header bg-white d-flex justify-content-between align-items-center">
            <h2 className="h5 mb-0">Users</h2>
            <span className="badge text-bg-light border">{users.length} records</span>
          </div>
          <div className="table-responsive">
            <table className="table table-hover align-middle mb-0 admin-mentor-table">
              <thead className="table-light">
                <tr>
                  <th>User</th>
                  <th>Role</th>
                  <th>Status</th>
                  <th>Email verified</th>
                  <th>Business data</th>
                  <th>Last login</th>
                  <th className="text-end">Action</th>
                </tr>
              </thead>
              <tbody>
                {users.map((user) => {
                  const canBlock = user.status !== 'BLOCKED';
                  const nextStatus = canBlock ? 'BLOCKED' : 'ACTIVE';

                  return (
                    <tr key={user.id}>
                      <td>
                        <strong className="d-block">{user.name}</strong>
                        <span className="small text-secondary">{user.email}</span>
                      </td>
                      <td>{user.role}</td>
                      <td>
                        <StatusBadge status={user.status} />
                      </td>
                      <td>{user.emailVerified ? 'Verified' : 'Not verified'}</td>
                      <td>
                        <span className="small d-block">{user.activeEnrollments} enrollments</span>
                        <span className="small text-secondary">{user.successPayments} success payments</span>
                      </td>
                      <td>{formatDateTime(user.lastLoginAt)}</td>
                      <td className="text-end">
                        <button
                          className={`btn btn-sm ${canBlock ? 'btn-outline-danger' : 'btn-outline-success'}`}
                          disabled={updatingUserId === user.id}
                          onClick={() => handleStatusChange(user, nextStatus)}
                          type="button"
                        >
                          {updatingUserId === user.id ? 'Updating...' : canBlock ? 'Block' : 'Activate'}
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      ) : null}
    </AdminMentorLayout>
  );
}
